load(){try{const raw=localStorage.getItem('breakout_achievements_v1');if(raw){const data=JSON.parse(raw);this.unlocked=data.unlocked||{};this.lifetimeModes=data.lifetimeModes||{};this.lifetimeLevels=data.lifetimeLevels||{}}}catch(e){this.unlocked={};this.lifetimeModes={};this.lifetimeLevels={}}}
